demos.key_concepts:
[
  {
    "concept": "การใช้ Present Simple Tense สำหรับเหตุการณ์ทั่วไปและความจริง",
    "importance": "high"
  },
  {
    "concept": "โครงสร้างประโยคบอกเล่า: Subject + Verb (s/es) + Complement",
    "importance": "high"
  },
  {
    "concept": "การใช้ do/does ในประโยคคำถามและปฏิเสธ",
    "importance": "high"
  },
  {
    "concept": "กฎการเติม -s หรือ -es ที่คำกริยาเมื่อประธานเป็นเอกพจน์",
    "importance": "medium"
  },
  {
    "concept": "การใช้คำบอกเวลา (e.g., every day, usually, sometimes)",
    "importance": "medium"
  }
]

[
  {
    "concept": "การไหลเวียนเลือดแบบเปิด vs แบบปิด",
    "importance": "high"
  },
  {
    "concept": "โครงสร้างและหน้าที่ของหัวใจและลิ้นหัวใจ",
    "importance": "high"
  },
  {
    "concept": "เส้นทางการไหลเวียนเลือดผ่านหัวใจและร่างกาย",
    "importance": "high"
  },
  {
    "concept": "ประเภทและหน้าที่ของเซลล์เม็ดเลือด",
    "importance": "medium"
  },
  {
    "concept": "ระบบภูมิคุ้มกันโดยกำเนิด vs จำเพาะ และการเปรียบเทียบภูมิคุ้มกันก่อเองกับรับมา",
    "importance": "medium"
  }
]

[
  {
    "concept": "นิยามและโครงสร้างของเมทริกซ์",
    "importance": "high"
  },
  {
    "concept": "การบวกและลบเมทริกซ์ (ต้องมีมิติเท่ากัน)",
    "importance": "high"
  },
  {
    "concept": "การคูณเมทริกซ์ด้วยจำนวนจริงและการคูณเมทริกซ์กับเมทริกซ์",
    "importance": "high"
  },
  {
    "concept": "คุณสมบัติการคูณเมทริกซ์ที่ไม่เหมือนการคูณจำนวนจริง",
    "importance": "medium"
  },
  {
    "concept": "การระบุตำแหน่งของสมาชิกในเมทริกซ์ (aij)",
    "importance": "medium"
  }
]

[
  {
    "concept": "โครงสร้างของนิทานชาดก",
    "importance": "high"
  },
  {
    "concept": "ทศชาติและทศบารมี",
    "importance": "high"
  },
  {
    "concept": "ประวัติความเป็นมาและสำนวนต่าง ๆ ของมหาเวสสันดรชาดก",
    "importance": "high"
  },
  {
    "concept": "ประเพณีการเทศน์มหาชาติและพิธีกรรมที่เกี่ยวข้อง",
    "importance": "medium"
  },
  {
    "concept": "ลักษณะคำประพันธ์ร่ายยาว",
    "importance": "medium"
  }
]

[
  {
    "concept": "การผลิตไฟฟ้าจากแหล่งพลังงานต่าง ๆ",
    "importance": "high"
  },
  {
    "concept": "การแปลงไฟฟ้า DC เป็น AC ด้วยอินเวอร์เตอร์",
    "importance": "high"
  },
  {
    "concept": "การคำนวณค่าไฟฟ้าจากหน่วย kWh และอัตราค่าไฟ",
    "importance": "high"
  },
  {
    "concept": "ขั้นตอนการติดตั้งระบบโซลาร์เซลล์ในบ้าน",
    "importance": "medium"
  },
  {
    "concept": "การประเมินผลตอบแทนจากการลงทุน (ROI) ของระบบโซลาร์เซลล์",
    "importance": "medium"
  }
]

[
  {
    "concept": "วงจรการนอนหลับและการขาด Deep Sleep",
    "importance": "high"
  },
  {
    "concept": "ผลกระทบของความเครียดและความวิตกกังวลต่อคุณภาพการนอน",
    "importance": "high"
  },
  {
    "concept": "ความสำคัญของการนอนให้เป็นเวลาและนาฬิกาชีวิต (Circadian Rhythm)",
    "importance": "high"
  },
  {
    "concept": "การปรับสภาพแวดล้อมการนอน (แสง เสียง กลิ่น ที่นอน)",
    "importance": "medium"
  },
  {
    "concept": "เทคนิคการผ่อนคลายก่อนนอน เช่น การหายใจลึก ๆ และการจินตนาการ",
    "importance": "medium"
  }
]

[
  {
    "concept": "ความแตกต่างระหว่างธาตุ สารประกอบ และของผสม",
    "importance": "high"
  },
  {
    "concept": "สมบัติของธาตุโลหะ อโลหะ และกึ่งโลหะ",
    "importance": "high"
  },
  {
    "concept": "การเกิดสารประกอบและการมีอัตราส่วนธาตุคงที่",
    "importance": "medium"
  },
  {
    "concept": "ตัวอย่างของแต่ละประเภทในชีวิตประจำวัน",
    "importance": "medium"
  },
  {
    "concept": "การแยกสารด้วยวิธีทางเคมีและนิวเคลียร์",
    "importance": "low"
  }
]

